ss=&#34;token operator&#34;&gt;&gt;&gt;&lt;/span&gt;maze&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;i&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;j&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;24&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;			&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;25&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;		&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;26&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;		&lt;span class=&#34;token keyword&#34;&gt;for&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;int&lt;/span&gt; i&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;i&lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;M&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;i&lt;span class=&#34;token operator&#34;&gt;++&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;27&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;			&lt;span class=&#34;token keyword&#34;&gt;for&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;int&lt;/span&gt; j&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;j&lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;N&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;j&lt;span class=&#34;token operator&#34;&gt;++&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;28&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;				&lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;!&lt;/span&gt;book&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;i&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;j&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;29&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;					room&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;30&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;					roomnum&lt;span class=&#34;token operator&#34;&gt;++&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;31&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;					&lt;span class=&#34;token function&#34;&gt;dfs&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;i&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;j&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;32&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;					maxroom&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;max&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;maxroom&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;room &lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;33&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;				&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;34&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;			&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;35&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;		&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;36&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;		cout&lt;span class=&#34;token operator&#34;&gt;&amp;lt;&amp;lt;&lt;/span&gt;roomnum&lt;span class=&#34;token operator&#34;&gt;&amp;lt;&amp;lt;&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34; &#34;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&amp;lt;&amp;lt;&lt;/span&gt;maxroom&lt;span class=&#34;token operator&#34;&gt;&amp;lt;&amp;lt;&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;\n&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;37&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;	&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;38&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;	&lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;39&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h2 id=&#34;g-徐半仙的数学问题&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#g-徐半仙的数学问题&#34;&gt;#&lt;/a&gt; G 徐半仙的数学问题&lt;/h2&gt;
&lt;blockquote&gt;
&lt;ul&gt;
&lt;li&gt;描述&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;已知有 a,b,c,d 四个正整数求满足下列两个等式的 x 的个数。&lt;/p&gt;
&lt;p&gt;&lt;em&gt;gcd&lt;/em&gt; (&lt;em&gt;x, a&lt;/em&gt;) = &lt;em&gt;b&lt;/em&gt;&lt;/p&gt;
&lt;p&gt;&lt;em&gt;lcm&lt;/em&gt; (&lt;em&gt;x, c&lt;/em&gt;) = &lt;em&gt;d&lt;/em&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;输入数据&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;第一行输入一个整数 T，表示测试的组数&lt;/p&gt;
&lt;p&gt;第 2 行到 T+1 行，每行 4 个整数，分别表示 a,b,c,d. 数据保证 a 能够被 b 整除，d 能够被 c 整除&lt;/p&gt;
&lt;p&gt;1 &lt;em&gt;&amp;lt;&lt;/em&gt;= &lt;em&gt;T &amp;lt;&lt;/em&gt;= 2000&lt;/p&gt;
&lt;p&gt;1 &lt;em&gt;&amp;lt;&lt;/em&gt;= &lt;em&gt;a, b, c, d &amp;lt;&lt;/em&gt;= 2&lt;em&gt;e&lt;/em&gt;9&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;输出数据&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;共 T 行，每行一个整数，如果不存在这样的 x, 输出 0, 否则，输出满足条件的 x 的个数&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;样例输入&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code&gt;4

41 1 96 288

95 1 37 1776

8481 1 999976991 1999953982

32560 2 999992632 1999985264
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;样例输出&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code&gt;6

2

4

0
&lt;/code&gt;&lt;/pre&gt;
&lt;/blockquote&gt;
&lt;h3 id=&#34;分析-4&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#分析-4&#34;&gt;#&lt;/a&gt; 分析&lt;/h3&gt;
&lt;p&gt;考察了唯一分解定理求 lcm 和 gcd，打一个素数表，枚举素数，打出质因子表。详细看&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuYmlsaWJpbGkuY29tL3ZpZGVvL0JWMVVjNDExaDdZcQ==&#34;&gt; bilibili&lt;/span&gt;&lt;/p&gt;
&lt;h3 id=&#34;code-4&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#code-4&#34;&gt;#&lt;/a&gt; CODE&lt;/h3&gt;
&lt;pre&gt;&lt;code&gt;#include &amp;lt;iostream&amp;gt;
#include &amp;lt;algorithm&amp;gt;
#include &amp;lt;string&amp;gt;
#include &amp;lt;cstring&amp;gt;
#include &amp;lt;map&amp;gt;
#include &amp;lt;set&amp;gt;
#include &amp;lt;deque&amp;gt;
#include &amp;lt;queue&amp;gt;
#include &amp;lt;vector&amp;gt;
#include &amp;lt;cstring&amp;gt;
#include &amp;lt;cstdio&amp;gt;
#include &amp;lt;cstdlib&amp;gt;
#include &amp;lt;cmath&amp;gt;
#define ios ios_base::sync_with_stdio(0),cin.tie(0),cout.tie(0)
#define debug  freopen(&amp;quot;in.txt&amp;quot;,&amp;quot;r&amp;quot;,stdin),freopen(&amp;quot;out.txt&amp;quot;,&amp;quot;w&amp;quot;,stdout);
#define PI acos(-1)
#define fs first
#define sc second
using namespace std;
typedef long long ll;
typedef pair&amp;lt;int,int&amp;gt; pii;
const ll maxn = 1e6+10;
double eps = 1e-8;

int T;
int a0,a1,b0,b1;
bool vis[maxn];
int P[maxn],tail;
struct node&amp;#123;
    int a,b,c,d;
&amp;#125;;
map&amp;lt;int,node&amp;gt; mp;
void initP(int N)&amp;#123;
    for(int i = 2;i&amp;lt;=N;i++)&amp;#123;
        if(!vis[i]) P[tail++] = i;
        for(int j = 0;P[j]&amp;lt;=N/i;j++)&amp;#123;
            vis[P[j]*i] = true;
            if(i%P[j] == 0) break;
        &amp;#125;
    &amp;#125;
&amp;#125;
void divP()&amp;#123;
    int idx = 0;
    for(int t:&amp;#123;a0,a1,b0,b1&amp;#125;)&amp;#123;
        ++idx;
        for(int j = 0;j&amp;lt;tail &amp;amp;&amp;amp; P[j]*P[j] &amp;lt;=t;j++)&amp;#123;
            if(t%P[j] == 0)&amp;#123;
                int cnt = 0;
                while(t%P[j] == 0)&amp;#123;
                    cnt++;
                    t/=P[j];
                &amp;#125;
                if(idx == 1) mp[P[j]].a = cnt;
                if(idx == 2) mp[P[j]].b = cnt;
                if(idx == 3) mp[P[j]].c = cnt;
                if(idx == 4) mp[P[j]].d = cnt;
            &amp;#125;
        &amp;#125;
        if(t&amp;gt;1)&amp;#123;
            if(idx == 1) mp[t].a = 1;
            if(idx == 2) mp[t].b = 1;
            if(idx == 3) mp[t].c = 1;
            if(idx == 4) mp[t].d = 1;
        &amp;#125;
    &amp;#125;
&amp;#125;
ll fun()&amp;#123;
    ll res = 1;
    for(auto p:mp)&amp;#123;
        node cur = p.second;
        int a = cur.a,b = cur.b,c = cur.c,d = cur.d;
        int cnt = 0;
        for(int i = 0;i&amp;lt;=31;i++)&amp;#123;
            if(min(i,a) == b &amp;amp;&amp;amp; max(i,c) == d) cnt++;
        &amp;#125;
        res *= cnt;
    &amp;#125;
    return res;
&amp;#125;
int main()&amp;#123;
    ios;
    initP(1&amp;lt;&amp;lt;16);
    cin&amp;gt;&amp;gt;T;
    while(T--)&amp;#123;
        cin&amp;gt;&amp;gt;a0&amp;gt;&amp;gt;a1&amp;gt;&amp;gt;b0&amp;gt;&amp;gt;b1;
        mp.clear();
        divP();
        cout&amp;lt;&amp;lt;fun()&amp;lt;&amp;lt;endl;
    &amp;#125;
    return 0;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
